fn calculate_discount(price: f64, discount_rate: f64) -> f64 {
    let mut discounted_price = price;
    if discount_rate < 0.5 {
        apply_normal_discount(&mut discounted_price, discount_rate);
    } else {
        apply_high_discount(&mut discounted_price, discount_rate);
    }
    discounted_price
}

fn apply_normal_discount(price: &mut f64, rate: f64) {
    *price -= price * rate;
}

fn apply_high_discount(price: &mut f64, rate: f64) {
    *price -= price * (rate * 1.2);
}
```

This makes the code more modular.

